var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……대답하실 필요 없습니다.","JPN":"……お答えする必要はございません。","ENG":"There's no need to answer that.","TWN":"……你不需要回答。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"자세한 것은 제가 말씀드리죠. 당신들은 제 손님이니까요.","JPN":"詳しいことは私から伝えます。あなた方は私のお客様ですから。","ENG":"I will tell you all the details. You are my guests, after all.","TWN":"就由我來代為回答吧，畢竟你們是我的客人！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"서, 성녀님! 어째서 이런 곳에?!","JPN":"せ、聖女様！　どうしてこんな所に！？","ENG":"Y-your Holiness! What brings you here?!","TWN":"是…聖女！您怎麼會出現在這裡？！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그보다 손님이라니……. 설마 저들에 대해 알고 계십니까?","JPN":"それよりお客様だとは……あの者たちをご存知でしょうか？","ENG":"And did you say guests? Does Your Holiness know something about them?","TWN":"您說他們是客人……難道您認識他們嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"외람되오나, 저들은 정체 모를 이방인입니다.","JPN":"僭越ながら申し上げますが、彼らは正体不明の異邦人です。","ENG":"With all due respect, they are complete strangers from a foreign land.","TWN":"恕小的直言，他們是身分不明的外邦人。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"마왕의 하수인일 가능성도 아직 완전히 배제할 수 없습니다. 자리를 피하십시오.","JPN":"魔王の手下である可能性もまだ否定できません。どうかこの場から離れてください。","ENG":"We have yet to rule out the possibility they serve the Demon Lord. Please get yourself to safety.","TWN":"目前也尚未完全排除他們是魔王手下的可能性，還請您不要插手。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아뇨. 저들은 마왕의 하수인이 아닙니다.","JPN":"いいえ、彼らは魔王の手下ではありません。","ENG":"No. They do not serve the Demon Lord.","TWN":"不，他們不是魔王的手下。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그런 건 오래 전에 모두 사라졌으니까요.","JPN":"そんなものは遠い昔にすべて消えていますから。","ENG":"Because all of that has long expired.","TWN":"根本沒這回事。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"예? 그게 무슨 말씀이신지……?","JPN":"はい？　それはどういう……","ENG":"What? I beg your pardon, but…","TWN":"什麼？那是什麼意思……？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"알렌 님께서 자리를 비우신 바람에 위장 마법의 효과가 약해졌나 보군요.","JPN":"アレン様のご不在で偽装魔法の効果が弱まったようですね。","ENG":"It appears the concealment spell has grown weak with Sir Allen's absence.","TWN":"艾倫離開後，偽裝術的法力似乎變弱了。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그렇지 않다면, 외부인들이 이 <color=#ffd34c>성역의 잔재</color>에 발을 들일 수 있을 리 없으니까요.","JPN":"そうでなければ、外部の人間がこの<color=#ffd34c>聖域の残滓</color>に足を踏み入れることができるはずがありません。","ENG":"Otherwise, outsiders would not be able to set foot into these <color=#ffd34c>remains of sanctuary</color>.","TWN":"否則外面的人怎麼可能進到<color=#ffd34c>聖域幻境</color>呢？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알렌 선생님을 알고 있어?","JPN":"アレン先生を知っているの？","ENG":"You know Allen? Birmingham?","TWN":"你認識艾倫老師？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선생님을 만나게 해 줘. 우린 그 사람과 할 얘기가 있어.","JPN":"先生に会わせて。私たちはあの人に話がある。","ENG":"Please let us meet him. We have something to discuss with him.","TWN":"讓我見他，我們有話要跟他說！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"돌아가세요. 저주받은 늑대여.","JPN":"帰りなさい、呪われた狼よ。","ENG":"Please leave. Ye Cursed Wolf.","TWN":"受詛咒的狼，你請回吧！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신은 아직 이 신성한 땅에 다다를 자격을 갖추지 못했습니다.","JPN":"あなたはまだこの神聖な地に辿り着く資格を備えておりません。","ENG":"You have yet to prove yourself worthy of reaching this sacred ground.","TWN":"你還沒有資格踏上這塊神聖的土地。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"본래는 허락 없이 이 땅에 발을 들인 것만으로도 크나큰 죄를 범한 것입니다.","JPN":"本来は許可無しでこの地に足を踏み入れただけでも大罪なのです。","ENG":"Normally, merely setting foot here without permission would constitute a grave crime.","TWN":"原本未經許可就擅自踏上這塊土地是要重重治罪的。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"지금은 그저 나의 구원자님께서 징벌을 명하지 않으셨기에 묵인해 드리고 있을 뿐이죠.","JPN":"今はただ、我が救世主様が懲罰を命じられていないので黙認しているにすぎません。","ENG":"I've merely turned a blind eye because my Savior has not ordered your punishment.","TWN":"現在只是因為我的救贖者大人尚未下令懲處，才暫時放任你們。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"미안하지만 그냥은 못 돌아가겠어.","JPN":"悪いけど、このまま引き返すことはできない。","ENG":"Sorry, but I can't just leave like this.","TWN":"很抱歉，我們無法就這樣回去！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이제 겨우 실마리를 찾았는데, 포기하란다고 얌전히 포기할 것 같아?","JPN":"やっと手がかりを見つけたのに、帰れと言われて大人しく諦めると思う？","ENG":"I found a lead. I'm not going to give up just because you tell me to.","TWN":"現在好不容易才找到一點線索，你要我回去我就要乖乖回去嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……당신이라면 그렇게 말할 줄 알았습니다.","JPN":"……あなたならそう言うと思いました。","ENG":"…I had a feeling you'd say that.","TWN":"……我就知道你會這麼說。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 저는 당신에 대해 어떠한 친애의 감정도 없는 바.","JPN":"しかし、私はあなたに対していかなる親愛の感情も持ち合わせていません。","ENG":"But I have not any kindred feelings for thee.","TWN":"不過我對你沒有任何的感情成分在，"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"스스로 자비를 거부하겠다면 율법대로 징벌할 뿐입니다.","JPN":"自ら慈悲を拒否するなら、法に則り懲罰を与えましょう。","ENG":"If you should refuse my mercy, I must prosecute you according to the law.","TWN":"如果你不願意接受我的好意，那我也只好照律例懲罰你。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"미안하군요. 기사대장 재클린, 그리고 방위 기사단 여러분.","JPN":"申し訳ありません。騎士隊長ジャクリーン、そして防衛騎士団の皆さん。","ENG":"My deepest regrets. Captain Jacques and knights of the Capital Defense Order.","TWN":"抱歉囉！杰克林隊長，還有其他護衛騎士團的成員們。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"허나 제국과 구원자님을 위한 희생입니다. 이번에도 겸허히 받아들이세요.","JPN":"帝国と救世主のための犠牲です。謙虚に受け止めてください。","ENG":"But this is for the Empire and the Savior. I hope you'll humbly accept this sacrifice once again.","TWN":"你們是為帝國和救贖者大人而犧牲，這次也默默接受吧。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"네? 무슨 말씀이십니까, 성녀님?","JPN":"はい？　それはどういう意味でしょうか、聖女様？","ENG":"Pardon? What does Your Holiness mean, sacrifice?","TWN":"什麼？您這是什麼意思？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"커헉……?!","JPN":"ぐはっ……！？","ENG":"Ack…?!","TWN":"嗚……？！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L34_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"끄윽, 아아아아악!!","JPN":"くうっ、ぐあああぁぁ……！！","ENG":"Hngh… Aaaah!!","TWN":"呃啊啊啊啊！！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"기사들이…… 침식체로 변하고 있어?","JPN":"騎士たちが……侵食体に変わっている！？","ENG":"The knights… are turning into C.O.s?","TWN":"騎士們……正在變成侵蝕體？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"뭘 보고만 있어?! 변이가 끝나기 전에 먼저 공격해야 해!","JPN":"何黙って見てるの！　変異が終わるよりも先に攻撃しないと！","ENG":"Don't just stand there! We must attack before they finish transforming!","TWN":"你在看表演啊？！趕快趁他們完全變成侵蝕體前先下手為強！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마 지금까지 숲에서 싸운 침식체들도…… 저 사람들이 변이한 거야?","JPN":"まさか、今まで森で戦った侵食体も……あの人たちが変異したものなの？","ENG":"Wait… All those C.O.s we fought in the forest… Were they people too?","TWN":"該不會我們之前在森林裡遇到的侵蝕體……也是那些人變異而成的？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그건 나중에 저 성녀인지 마녀인지 하는 여자에게 물어 봐!","JPN":"それは後であの聖女なのか魔女なのかわからない女に聞いてみて！","ENG":"You can ask that witch, or saintess, or whatever the hell she is later!","TWN":"這個等之後再問那個不知道是聖女還魔女的女人啦！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"호오, 기사단과의 결투에 이어서 타락한 성녀의 등장인가?","JPN":"ふんふん、騎士団との決闘に続いて堕落した聖女の登場？","ENG":"Ooh, first a battle with the knights and now a fallen saintess?","TWN":"哇喔！和騎士團的戰鬥之後，緊接登場的是墮落的聖女嗎？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이번 스테이지를 돌파하면 그 마왕이라는 녀석과 싸우게 되는 모양이지.","JPN":"今回のステージを突破したら、あの魔王っていうやつと戦えるのかしら。","ENG":"I guess we'll get to fight the Demon Lord if we clear this stage.","TWN":"這場打完接下來應該就是大魔王登場吧？！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이 정도로 공들인 퍼포먼스라니 제법이야! 나중에 경품으로 뭘 줄지 기대되는걸?!","JPN":"ここまで手が込んだパフォーマンスなんて\\n中々やるじゃない！　後でどんな景品がもらえるか楽しみね！！","ENG":"Seriously, I'm impressed with the show so far! I wonder what kind of prizes you'll give out later.","TWN":"很用心的表演欸！好期待最後會送什麼獎品喔！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};